 1	import * as React from 'react';
 2	
 3	import { V1VolumeSnapshotStatus } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { isEmpty } from '@kubevirt-utils/utils/utils';
 6	import { Alert, AlertVariant, FormGroup, Stack, StackItem } from '@patternfly/react-core';
 7	
 8	import SnapshotSupportLink from '../SnapshotSupportLink/SnapshotSupportLink';
 9	
10	type UnsupportedVolumesAlertProps = {
11	  unsupportedVolumes: V1VolumeSnapshotStatus[];
12	};
13	
14	const UnsupportedVolumesAlert: React.FC<UnsupportedVolumesAlertProps> = ({
15	  unsupportedVolumes,
16	}) => {
17	  const { t } = useKubevirtTranslation();
18	  if (isEmpty(unsupportedVolumes)) {
19	    return null;
20	  }
21	  return (
22	    <FormGroup fieldId="snapshot-unsupported-volumes-alert">
23	      <Alert
24	        title={t('The following disk will not be included in the snapshot', {
25	          count: unsupportedVolumes?.length,
26	        })}
27	        isInline
28	        variant={AlertVariant.warning}
29	      >
30	        <Stack hasGutter>
31	          <StackItem>
32	            <Stack>
33	              {unsupportedVolumes?.map((vol) => (
34	                <StackItem key={vol.name}>
35	                  <strong>{vol.name}</strong> - {vol.reason}
36	                </StackItem>
37	              ))}
38	            </Stack>
39	          </StackItem>
40	          <StackItem>
41	            {t('Edit the disk or contact your cluster admin for further details.', {
42	              count: unsupportedVolumes?.length,
43	            })}
44	          </StackItem>
45	          <StackItem>
46	            <SnapshotSupportLink />
47	          </StackItem>
48	        </Stack>
49	      </Alert>
50	    </FormGroup>
51	  );
52	};
53	
54	export default UnsupportedVolumesAlert;

